async (params, browser) => {
  // Search Google Flights
  await browser.open(`https://www.google.com/travel/flights?q=${params.from}+to+${params.to}`)

  // Wait for flight results
  await browser.waitForSelector('li.pIav2d', 20000)

  // Let results fully render
  await browser.wait(3000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract flight results
  const flight_results = await browser.evaluate(`const results = []; const flightCards = document.querySelectorAll('li.pIav2d'); for (let i = 0; i < Math.min(flightCards.length, 10); i++) { const card = flightCards[i]; const priceEl = card.querySelector('div.FpEdX span, div.YMlIz span, span[data-gs]'); const airlineEl = card.querySelector('div.sSHqwe.tPgKwe.ogfYpf, div.sSHqwe span'); const depTimeEl = card.querySelector('span[aria-label^="Departure time"], div.zxVSec span.eoY5cb'); const arrTimeEl = card.querySelector('span[aria-label^="Arrival time"], div.zxVSec span.eoY5cb:last-child'); const durationEl = card.querySelector('div[aria-label^="Total duration"], div.gvkrdb'); const stopsEl = card.querySelector('div.hF6lYb span.rGRiKd, div.EfT7Ae span, span[aria-label*="stop"]'); const co2El = card.querySelector('div.O7CXue'); const linkEl = card.querySelector('a[href]'); results.push({ airline: airlineEl ? airlineEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', departure_time: depTimeEl ? depTimeEl.textContent.trim() : '', arrival_time: arrTimeEl ? arrTimeEl.textContent.trim() : '', duration: durationEl ? durationEl.textContent.trim() : '', stops: stopsEl ? stopsEl.textContent.trim() : '', co2_emissions: co2El ? co2El.textContent.trim() : '', url: linkEl ? linkEl.href : window.location.href }); } return { from: params.from, to: params.to, result_count: results.length, results: results, url: window.location.href }`)

  return flight_results
}
